+// Look up color by topic id (format: "changelog-{projectId}")
+const getTopicColor = (id: string | undefined): string | undefined => {
+  if (!id?.startsWith('changelog-')) return undefined;
+  const projectId = id.slice('changelog-'.length);
+  return changelogProjects[projectId as keyof typeof changelogProjects]?.color;
 };

